python3 - <<'PY'
import json
from pathlib import Path
p=Path('/tmp/geo_strategy_data.json')
stores=json.loads(p.read_text(encoding='utf-8'))
for s in stores:
    for model,meta in s['models'].items():
        eid=f"geo-strategy-{s['id']}-{model}"
        print(json.dumps({
            'entityType':'geo-strategy','entityId':eid,
            'message':f"Create GEO strategy for {s['name']} on {model}",
            'data':{
                'storeId':s['id'],'storeName':s['name'],'city':s['city'],'model':model,
                'targetMindshare':meta['mindshare'],'triggerScenarios':meta['triggers'],
                'avoidScenarios':meta['avoid'],'priorityFields':meta['fields'],
                'expressionStyle':meta['style'],'strategicImpact':'medium',
                'approvalStatus':'not-required','status':'active'
            }
        }, ensure_ascii=False))
PY

